#include <vector>
using namespace std;

class FenwickTree {
    vector<long long> tree;
    int size;
public:
    FenwickTree(int size) : size(size), tree(size + 1, 0) {}
    void update(int index, long long delta) {
        index += 1; // convert to 1-based
        while (index <= size) {
            tree[index] += delta;
            index += index & -index;
        }
    }
    long long query(int index) {
        index += 1; // convert to 1-based
        long long res = 0;
        while (index > 0) {
            res += tree[index];
            index -= index & -index;
        }
        return res;
    }
    long long range_query(int l, int r) {
        return query(r) - query(l - 1);
    }
};

long long compute_depth(long long x) {
    long long depth = 0;
    while (x != 1) {
        x = __builtin_popcountll(x);
        depth++;
    }
    return depth;
}

vector<long long> solve(vector<long long> nums, vector<vector<long long>> queries) {
    int n = nums.size();
    vector<long long> depths(n);
    for (int i = 0; i < n; ++i) {
        depths[i] = compute_depth(nums[i]);
    }
    vector<FenwickTree> bits(6);
    for (int k = 0; k < 6; ++k) {
        bits[k] = FenwickTree(n);
    }
    for (int i = 0; i < n; ++i) {
        long long d = depths[i];
        bits[d].update(i, 1);
    }
    vector<long long> answer;
    for (auto& q : queries) {
        if (q[0] == 1) {
            int l = q[1], r = q[2], k = q[3];
            answer.push_back(bits[k].range_query(l, r));
        } else {
            int idx = q[1], val = q[2];
            long long new_depth = compute_depth(val);
            long long old_depth = depths[idx];
            bits[old_depth].update(idx, -1);
            bits[new_depth].update(idx, 1);
            nums[idx] = val;
            depths[idx] = new_depth;
        }
    }
    return answer;
}
