using namespace std;

class FenwickTree {
    vector<long long> tree;
public:
    FenwickTree(int size) : tree(size + 1, 0) {}
    void update(int index, int value) {
        while (index <= tree.size()) {
            tree[index] += value;
            index += index & -index;
        }
    }
    long long query(int index) {
        long long res = 0;
        while (index > 0) {
            res += tree[index];
            index -= index & -index;
        }
        return res;
    }
};

vector<long long> solve(vector<long long> nums, vector<vector<long long>> queries) {
    int n = nums.size();
    vector<int> depths(n);
    for (int i = 0; i < n; ++i) {
        long long x = nums[i];
        int d = 0;
        while (x != 1) {
            x = __builtin_popcountll(x);
            d++;
        }
        depths[i] = d;
    }

    const int MAX_DEPTH = 5;
    vector<FenwickTree> ft(MAX_DEPTH + 1, FenwickTree(n));

    for (int i = 0; i < n; ++i) {
        int d = depths[i];
        ft[d].update(i + 1, 1);
    }

